    dh = (y[:, :, 1:, :] - y[:, :, :-1, :]).abs()
    dw = (y[:, :, :, 1:] - y[:, :, :, :-1]).abs()
    if mask is None:
        return dh.mean() + dw.mean()
    mh = mask[:, :, 1:, :] * mask[:, :, :-1, :]
    mw = mask[:, :, :, 1:] * mask[:, :, :, :-1]
    return get_mean(dh, mh) + get_mean(dw, mw)

